struct HomeView:View{@EnvironmentObject var m:MusicModel;@EnvironmentObject var l:I18n;@Environment(\.openURL)var openURL;var body:some View{NavigationStack{List{if m.filtered.isEmpty{ContentUnavailableView(l.t("empty_catalog"),systemImage:"music.note",description:Text(l.t("retry")))}else{ForEach(m.filtered){TrackRow(t:$0)}}}.searchable(text:$m.query,prompt:l.t("search_hint")).navigationTitle(l.t("app_name")).toolbar{Button(l.t("sign_in_wallet")){if let u=try? WalletLink.make(){openURL(u)}}}.refreshable{await m.refresh()}}}}
struct LibraryView:View{@EnvironmentObject var m:MusicModel;@EnvironmentObject var l:I18n;@State var playlistName="";var body:some View{NavigationStack{List{Section(l.t("favorites")){ForEach(m.state.favorites,id:\.self){Text($0)}};Section(l.t("queue")){ForEach(m.state.queue,id:\.self){Text($0)}};Section(l.t("library")){TextField(l.t("library"),text:$playlistName);Button(l.t("upload")){Task{try? await m.api.createPlaylist(name:playlistName,ids:m.state.favorites)}}.disabled(playlistName.isEmpty||m.state.favorites.isEmpty)}}.navigationTitle(l.t("library"))}}}
struct CreatorView:View{@EnvironmentObject var m:MusicModel;@EnvironmentObject var l:I18n;@State var importing=false;@State var title="";@State var artist="";@State var evidence="";@State var provenance="";@State var aiStatus="";var body:some View{NavigationStack{Form{Text(l.t("creator_truth"));TextField(l.t("track_title"),text:$title);TextField(l.t("artist_name"),text:$artist);TextField(l.t("rights_evidence"),text:$evidence);TextField(l.t("provenance"),text:$provenance);Button(l.t("upload_owned_audio")){importing=true}.fileImporter(isPresented:$importing,allowedContentTypes:[.wav]){result in if case .success(let url)=result{Task{let access=url.startAccessingSecurityScopedResource();defer{if access{url.stopAccessingSecurityScopedResource()}};do{try await m.api.uploadOwnedWAV(url,title:title,artist:artist,evidence:evidence,provenance:provenance);await m.refresh()}catch{m.status="upload_failed"}}}};Section(l.t("usage_records")){Text(l.number(m.snapshot.usage.count))};Text(l.t("revenue_truth")).font(.footnote);Button(l.t("ai_enabled")){guard m.state.aiEnabled else{return};Task{do{aiStatus=try await m.api.createAI(ids:m.state.favorites,language:l.aiLanguage)}catch{aiStatus=l.t("retry")}}}.disabled(!m.state.aiEnabled||m.state.favorites.isEmpty);Text(aiStatus.isEmpty ? l.t("ai_explanation"):aiStatus).font(.footnote)}.navigationTitle(l.t("creator"))}}}
struct SettingsView:View{@EnvironmentObject var m:MusicModel;@EnvironmentObject var l:I18n;var body:some View{NavigationStack{Form{Picker(l.t("language"),selection:Binding(get:{l.tag},set:l.set)){Text("System").tag("system");ForEach(["en","zh-Hans","zh-Hant","ja","ko","es","fr","de","pt","ru","ar","id"],id:\.self){Text($0).tag($0)}};Toggle(l.t("ai_enabled"),isOn:Binding(get:{m.state.aiEnabled},set:m.setAI));Picker("AI output",selection:Binding(get:{l.aiLanguage},set:l.setAI)){Text("System").tag("system");ForEach(["en","zh-Hans","zh-Hant","ja","ko","es","fr","de","pt","ru","ar","id"],id:\.self){Text($0).tag($0)}};Text(l.t("ai_explanation"));Button(l.t("clear_private_data"),role:.destructive){Keychain.clear()}}.navigationTitle(l.t("settings"))}}}

@main struct YNXMusicApp:App{@StateObject var model=MusicModel();@StateObject var l=I18n.shared;var body:some Scene{WindowGroup{TabView{HomeView().tabItem{Label(l.t("home"),systemImage:"music.note.house")};LibraryView().tabItem{Label(l.t("library"),systemImage:"books.vertical")};CreatorView().tabItem{Label(l.t("creator"),systemImage:"waveform")};SettingsView().tabItem{Label(l.t("settings"),systemImage:"gear")}}.environmentObject(model).environmentObject(l).environment(\.locale,Locale(identifier:l.resolved)).environment(\.layoutDirection,l.rtl ? .rightToLeft:.leftToRight).tint(Color(red:0,green:47/255,blue:167/255)).onOpenURL{url in guard url.scheme=="ynxmusic",Date().timeIntervalSince1970<UserDefaults.standard.double(forKey:"walletExpires"),let response=URLComponents(url:url,resolvingAgainstBaseURL:false)?.queryItems?.first(where:{$0.name=="response"})?.value,let nonce=UserDefaults.standard.string(forKey:"walletNonce") else{return};UserDefaults.standard.removeObject(forKey:"walletNonce");UserDefaults.standard.removeObject(forKey:"walletExpires");Task{try? await model.api.walletSession(response:response,nonce:nonce)}}}}}
